insert into champion_tags (champion_id, tag_id, status, source_type, source_note, proposed_by, proposed_at, ascension_required)
select ch.id, t.id, 'proposed', 'raid_guide', 'raid.guide A2 Mass Impalement: [Decrease DEF] 50% unbooked (75% booked − 25% book). AoE (all enemies). Cooldown 4 unbooked, 3 fully booked.', 'raid-guide-scraper', now(), 0
from champions ch join tags t on t.name = 'Decrease Defense'
